import React, { useState, useRef } from 'react';
import { Package, DollarSign, Calendar, Image as ImageIcon, X, Upload, Hash, UserCheck } from 'lucide-react';

const FormularioOferta = ({ onSave, onCancel }) => {
  const fileInputRef = useRef(null);
  const [formData, setFormData] = useState({
    producto: '',
    precioViejo: '',
    precioNuevo: '',
    vencimiento: '',
    descripcion: '',
    stock: '',
    limitePorCliente: '',
    imagen: null
  });
  const [preview, setPreview] = useState(null);

  const handleImageChange = (e) => {
    const file = e.target.files[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setPreview(reader.result);
        setFormData({ ...formData, imagen: reader.result });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (parseFloat(formData.precioNuevo) >= parseFloat(formData.precioViejo)) {
      alert("El precio de oferta debe ser menor al precio anterior.");
      return;
    }
    onSave(formData);
  };

  return (
    <div style={formCardStyle}>
      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '20px' }}>
        <h3 style={{ margin: 0 }}>Publicar Oferta Especial</h3>
        <button onClick={onCancel} style={btnCerrar}><X size={20} /></button>
      </div>

      <form onSubmit={handleSubmit}>
        <div style={inputGroup}>
          <label style={labelStyle}><Package size={16} /> Nombre del Producto</label>
          <input 
            style={inputStyle} type="text" placeholder="Ej: Aceite de Girasol 1.5L" required
            value={formData.producto} onChange={(e) => setFormData({...formData, producto: e.target.value})}
          />
        </div>

        <div style={{ display: 'flex', gap: '15px' }}>
          <div style={{ ...inputGroup, flex: 1 }}>
            <label style={labelStyle}><DollarSign size={16} /> Precio Anterior</label>
            <input 
              style={inputStyle} type="number" placeholder="Precio normal" required
              value={formData.precioViejo} onChange={(e) => setFormData({...formData, precioViejo: e.target.value})}
            />
          </div>
          <div style={{ ...inputGroup, flex: 1 }}>
            <label style={labelStyle}><Tag size={16} color="#e67e22" /> Precio Oferta</label>
            <input 
              style={{...inputStyle, borderColor: '#e67e22'}} type="number" placeholder="Precio rebajado" required
              value={formData.precioNuevo} onChange={(e) => setFormData({...formData, precioNuevo: e.target.value})}
            />
          </div>
        </div>

        <div style={{ display: 'flex', gap: '15px' }}>
          <div style={{ ...inputGroup, flex: 1 }}>
            <label style={labelStyle}><Hash size={16} /> Stock Total</label>
            <input 
              style={inputStyle} type="number" placeholder="Cant. disponible" required
              value={formData.stock} onChange={(e) => setFormData({...formData, stock: e.target.value})}
            />
          </div>
          <div style={{ ...inputGroup, flex: 1 }}>
            <label style={labelStyle}><UserCheck size={16} /> Máx. por cliente</label>
            <input 
              style={inputStyle} type="number" placeholder="Límite" required
              value={formData.limitePorCliente} onChange={(e) => setFormData({...formData, limitePorCliente: e.target.value})}
            />
          </div>
        </div>

        <div style={inputGroup}>
          <label style={labelStyle}><ImageIcon size={16} /> Foto Real</label>
          <div style={dropzoneStyle} onClick={() => fileInputRef.current.click()}>
            {preview ? <img src={preview} alt="Preview" style={previewStyle} /> : 
            <div style={placeholderStyle}><Upload size={20} /><p>Subir foto</p></div>}
            <input type="file" ref={fileInputRef} onChange={handleImageChange} accept="image/*" style={{ display: 'none' }} />
          </div>
        </div>

        <button type="submit" style={btnPublicar}>Publicar Oferta</button>
      </form>
    </div>
  );
};

// ... Estilos anteriores + Tag importado de lucide-react ...
const Tag = ({size, color}) => <DollarSign size={size} style={{color}} />; // Alias temporal para el ejemplo
const formCardStyle = { background: 'white', padding: '25px', borderRadius: '20px', border: '1px solid #e2e8f0' };
const inputGroup = { marginBottom: '12px' };
const labelStyle = { display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '5px', fontWeight: '600', fontSize: '0.85rem' };
const inputStyle = { width: '100%', padding: '10px', borderRadius: '8px', border: '1px solid #cbd5e1', boxSizing: 'border-box' };
const dropzoneStyle = { border: '2px dashed #cbd5e1', borderRadius: '10px', height: '100px', display: 'flex', justifyContent: 'center', alignItems: 'center', cursor: 'pointer', background: '#f8fafc', overflow: 'hidden' };
const previewStyle = { width: '100%', height: '100%', objectFit: 'cover' };
const placeholderStyle = { textAlign: 'center', color: '#94a3b8', fontSize: '0.8rem' };
const btnPublicar = { width: '100%', padding: '12px', background: '#1e293b', color: 'white', border: 'none', borderRadius: '10px', fontWeight: 'bold', cursor: 'pointer' };
const btnCerrar = { background: 'none', border: 'none', cursor: 'pointer' };

export default FormularioOferta;
